def safe_divide(a, b):
    try:
        result = a / b
        print(f"{a} / {b} = {result}")
    except ZeroDivisionError:
        print("Cannot divide by zero!")

safe_divide(10, 2)
safe_divide(10, 0)
safe_divide(15, 3)

